-- ============================================================================
-- Quiz Seed: Deuteronomy — Part 4 (Chapters 31–34)
-- 3 difficulties × 4 chapters = 64 total questions
--   kids:   3 per chapter  = 12
--   teens:  5 per chapter  = 20
--   adults: 8 per chapter  = 32
-- ============================================================================

-- ═══ Deuteronomy Chapter 31 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 31, 'kids', 1, 'How old was Moses when he spoke his farewell to Israel in Deuteronomy 31?', 'One hundred and twenty years old', 'One hundred years old', 'Eighty years old', 'Ninety years old', 'a', 'Deuteronomy 31:2 — "I am an hundred and twenty years old this day; I can no more go out and come in."'),
('Deuteronomy', 31, 'kids', 2, 'Who did Moses say would lead Israel into the Promised Land after him?', 'Joshua', 'Caleb', 'Aaron', 'Eleazar', 'a', 'Deuteronomy 31:3 — "The LORD thy God, he will go over before thee, and he will destroy these nations from before thee, and thou shalt possess them: and Joshua, he shall go over before thee."'),
('Deuteronomy', 31, 'kids', 3, 'Where did Moses tell the priests to put the book of the law?', 'In the side of the ark of the covenant', 'Under the altar', 'In the tabernacle door', 'Beside the mercy seat', 'a', 'Deuteronomy 31:26 — "Take this book of the law, and put it in the side of the ark of the covenant of the LORD your God, that it may be there for a witness against thee."'),
-- Teens
('Deuteronomy', 31, 'teens', 1, 'What did Moses tell the people not to be afraid of, and why?', 'He told them not to fear the nations of Canaan because God would go before them', 'He told them not to fear the wilderness because water would be provided', 'He told them not to fear Pharaoh because he was already defeated', 'He told them not to fear death because Moses would pray for them', 'a', 'Deuteronomy 31:6 — "Be strong and of a good courage, fear not, nor be afraid of them: for the LORD thy God, he it is that doth go with thee; he will not fail thee, nor forsake thee."'),
('Deuteronomy', 31, 'teens', 2, 'What did God say the Israelites would do after Moses died?', 'They would forsake God and follow other gods of the land', 'They would build a great temple to the LORD', 'They would return to Egypt immediately', 'They would divide the land and live in peace forever', 'a', 'Deuteronomy 31:16 — "This people will rise up, and go a whoring after the gods of the strangers of the land, whither they go to be among them, and will forsake me, and break my covenant which I have made with them."'),
('Deuteronomy', 31, 'teens', 3, 'What was the purpose of the song God commanded Moses to write?', 'To be a witness against Israel when they sinned', 'To praise God for the Exodus from Egypt', 'To teach the law to future generations', 'To honor Joshua as the new leader', 'a', 'Deuteronomy 31:19 — "Now therefore write ye this song for you, and teach it the children of Israel: put it in their mouths, that this song may be a witness for me against the children of Israel."'),
('Deuteronomy', 31, 'teens', 4, 'How often were the priests commanded to read the law to all Israel?', 'Every seven years at the feast of tabernacles', 'Every year at Passover', 'Every Sabbath in the tabernacle', 'Every jubilee year', 'a', 'Deuteronomy 31:10-11 — "At the end of every seven years...in the feast of tabernacles...thou shalt read this law before all Israel in their hearing."'),
('Deuteronomy', 31, 'teens', 5, 'What did God say would happen to Israel in the latter days?', 'Evil would befall them because they would turn from God', 'They would rule all surrounding nations', 'God would give them rest from all enemies', 'They would return to Egypt and be delivered again', 'a', 'Deuteronomy 31:29 — "For I know that after my death ye will utterly corrupt yourselves, and turn aside from the way which I have commanded you; and evil will befall you in the latter days."'),
-- Adults
('Deuteronomy', 31, 'adults', 1, 'What specific phrase did Moses use to describe his inability to lead Israel, and what reason did he give?', 'He said he could "no more go out and come in" because God had said he would not cross Jordan', 'He said he was too old to command the army and would rest in his tent', 'He said his eyesight had failed and he could not see the path forward', 'He said his strength had left him and he could no longer speak plainly', 'a', 'Deuteronomy 31:2 — "I am an hundred and twenty years old this day; I can no more go out and come in: also the LORD hath said unto me, Thou shalt not go over this Jordan."'),
('Deuteronomy', 31, 'adults', 2, 'What did God tell Moses He would do to the nations of Canaan, using what imagery?', 'God said He would destroy them and Moses used the example of what He did to Sihon and Og', 'God said He would scatter them as He scattered the builders of Babel', 'God said He would send hornets before Israel as He did in Egypt', 'God said He would dry up their rivers as He dried up the Red Sea', 'a', 'Deuteronomy 31:4 — "And the LORD shall do unto them as he did to Sihon and to Og, kings of the Amorites, and unto the land of them, whom he destroyed."'),
('Deuteronomy', 31, 'adults', 3, 'What was the setting in which Moses formally commissioned Joshua before all Israel?', 'Moses called Joshua and said "Be strong and of a good courage" before all Israel in a public charge', 'Moses laid hands on Joshua privately in the tabernacle', 'Moses wrote Joshua''s name in the book of the law as successor', 'Moses anointed Joshua with oil at the altar of burnt offering', 'a', 'Deuteronomy 31:7 — "And Moses called unto Joshua, and said unto him in the sight of all Israel, Be strong and of a good courage."'),
('Deuteronomy', 31, 'adults', 4, 'What appearance did God make regarding Joshua''s commissioning, and where did it take place?', 'The LORD appeared in the tabernacle in a pillar of a cloud over the door, and commissioned Joshua there', 'The LORD appeared on Mount Sinai with thunder and lightning as He did before Moses', 'The LORD appeared in fire on the altar and spoke from the flame', 'The LORD appeared to Joshua alone in a dream that night after Moses died', 'a', 'Deuteronomy 31:15 — "And the LORD appeared in the tabernacle in a pillar of a cloud: and the pillar of the cloud stood over the door of the tabernacle."'),
('Deuteronomy', 31, 'adults', 5, 'What theological concept did God announce about His future relationship with Israel after their apostasy?', 'God said He would hide His face from them, and they would be devoured by evils and troubles', 'God said He would send them prophets to warn them before any punishment', 'God said He would reduce them to a small remnant but never destroy them entirely', 'God said He would give them over to their enemies for forty years as in the wilderness', 'a', 'Deuteronomy 31:17-18 — "Then my anger shall be kindled against them in that day, and I will forsake them, and I will hide my face from them...and I will surely hide my face in that day for all the evils which they shall have wrought."'),
('Deuteronomy', 31, 'adults', 6, 'What was the role of the Levites specified in connection with the book of the law?', 'They bore the ark of the covenant and were to take the book of the law and place it beside the ark', 'They were to memorize the entire book of the law and recite it annually', 'They were to make copies of the law for each of the twelve tribes', 'They were to teach the law in each city gate every Sabbath day', 'a', 'Deuteronomy 31:25-26 — "That Moses commanded the Levites, which bare the ark of the covenant of the LORD, saying, Take this book of the law, and put it in the side of the ark."'),
('Deuteronomy', 31, 'adults', 7, 'What were the "elders of the tribes" and "officers" summoned to hear at the end of Moses'' ministry?', 'Moses spoke the words of the song in their ears and called heaven and earth to record against Israel', 'Moses recited the entire law from beginning to end one final time', 'Moses announced the boundaries of each tribe''s inheritance in Canaan', 'Moses gave final instructions for the building of the temple', 'a', 'Deuteronomy 31:28-30 — "Gather unto me all the elders of your tribes, and your officers, that I may speak these words in their ears...and Moses spake in the ears of all the congregation of Israel the words of this song."'),
('Deuteronomy', 31, 'adults', 8, 'What striking contrast did Moses draw between the present day and the future in his final warning?', 'Moses said they were rebellious even while he was alive with them, so much more after his death', 'Moses said they had been faithful in the wilderness but would fail in the prosperity of Canaan', 'Moses said the children would be more faithful than their parents had been', 'Moses said the Promised Land itself would cause them to forget God because of its abundance', 'a', 'Deuteronomy 31:27 — "For I know thy rebellion, and thy stiff neck: behold, while I am yet alive with you this day, ye have been rebellious against the LORD; and how much more after my death?"');

-- ═══ Deuteronomy Chapter 32 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 32, 'kids', 1, 'What name does Moses give to God at the beginning of the Song of Moses?', 'The Rock', 'The Shepherd', 'The King', 'The Tower', 'a', 'Deuteronomy 32:4 — "He is the Rock, his work is perfect: for all his ways are judgment: a God of truth and without iniquity, just and right is he."'),
('Deuteronomy', 32, 'kids', 2, 'What bird does Moses compare God to as He cared for Israel in the wilderness?', 'An eagle', 'A dove', 'A sparrow', 'A hawk', 'a', 'Deuteronomy 32:11 — "As an eagle stirreth up her nest, fluttereth over her young, spreadeth abroad her wings, taketh them, beareth them on her wings."'),
('Deuteronomy', 32, 'kids', 3, 'What mountain was Moses told to climb to see the land of Canaan before he died?', 'Mount Nebo', 'Mount Sinai', 'Mount Carmel', 'Mount Hermon', 'a', 'Deuteronomy 32:49 — "Get thee up into this mountain Abarim, unto mount Nebo, which is in the land of Moab, that is over against Jericho; and behold the land of Canaan."'),
-- Teens
('Deuteronomy', 32, 'teens', 1, 'What metaphor does Moses use to describe how God''s teaching should be received by the people?', 'Rain and dew falling on tender grass and herbs', 'Fire refining gold and silver', 'A lamp illuminating a dark room', 'A sword dividing truth from falsehood', 'a', 'Deuteronomy 32:2 — "My doctrine shall drop as the rain, my speech shall distil as the dew, as the small rain upon the tender herb, and as the showers upon the grass."'),
('Deuteronomy', 32, 'teens', 2, 'Why did Moses call Israel "a froward and perverse generation"?', 'They had rewarded God''s fatherly care with corruption and unfaithfulness', 'They had refused to enter Canaan when God first commanded them', 'They had worshipped the golden calf while Moses was on Sinai', 'They had murmured against God continuously in the wilderness', 'a', 'Deuteronomy 32:5-6 — "They have corrupted themselves, their spot is not the spot of his children: they are a crooked and perverse nation...Do ye thus requite the LORD, O foolish people and unwise?"'),
('Deuteronomy', 32, 'teens', 3, 'What did Moses say God found Israel in when He first chose them?', 'A waste howling wilderness', 'The land of Egypt in bondage', 'The city of Ur of the Chaldees', 'A desert beside the sea', 'a', 'Deuteronomy 32:10 — "He found him in a desert land, and in the waste howling wilderness; he led him about, he instructed him, he kept him as the apple of his eye."'),
('Deuteronomy', 32, 'teens', 4, 'What did God say He would use to provoke Israel to jealousy because of their idolatry?', 'Those which are not a people, a foolish nation', 'The Egyptians they had left behind', 'The Philistines dwelling on the coast', 'The Assyrians from the north', 'a', 'Deuteronomy 32:21 — "They have moved me to jealousy with that which is not God; they have provoked me to anger with their vanities: and I will move them to jealousy with those which are not a people; I will provoke them to anger with a foolish nation."'),
('Deuteronomy', 32, 'teens', 5, 'What declaration did Moses make about God and other gods that affirms monotheism?', 'There is no god with God; He kills and makes alive, and none can deliver out of His hand', 'God alone created the heavens and earth and no other god had any part', 'God would destroy every idol in Canaan so that His name alone would be known', 'Other gods were fashioned by men''s hands and had no power at all', 'a', 'Deuteronomy 32:39 — "See now that I, even I, am he, and there is no god with me: I kill, and I make alive; I wound, and I heal: neither is there any that can deliver out of my hand."'),
-- Adults
('Deuteronomy', 32, 'adults', 1, 'What witnesses does Moses call at the opening of the song, and what does this literary device signify?', 'He calls heaven and earth as witnesses, invoking the permanence of creation to witness God''s covenant with Israel', 'He calls the elders and priests as witnesses to record his final words accurately', 'He calls the twelve tribes as collective witnesses to the covenant obligations', 'He calls upon future generations as witnesses by writing the song down', 'a', 'Deuteronomy 32:1 — "Give ear, O ye heavens, and I will speak; and hear, O earth, the words of my mouth."'),
('Deuteronomy', 32, 'adults', 2, 'How does Moses describe God''s sovereign allocation of the nations, and what is Israel''s special portion?', 'God separated the sons of Adam and set the bounds of people according to the number of the children of Israel; Jacob is His inheritance', 'God gave each nation its land based on the faithfulness of their ancestors', 'God assigned nations their territories by lot as He later did for the tribes of Israel', 'God set the nations apart according to the languages given at Babel', 'a', 'Deuteronomy 32:8-9 — "When the Most High divided to the nations their inheritance, when he separated the sons of Adam, he set the bounds of the people...For the LORD''S portion is his people; Jacob is the lot of his inheritance."'),
('Deuteronomy', 32, 'adults', 3, 'What specific agricultural abundance did God give Israel, and how did they respond to it?', 'God gave them honey from the rock, oil from the flinty rock, butter and milk, and Israel grew fat, thick, and scurrilous, and forsook God', 'God gave them the grain of Canaan and they immediately began offering it to Baal', 'God gave them vineyards and olive groves and they used the abundance for temple prostitution', 'God gave them the cattle of the land and they sacrificed to golden calves', 'a', 'Deuteronomy 32:13-15 — "He made him...suck honey out of the rock...But Jeshurun waxed fat, and kicked: thou art waxen fat, thou art grown thick, thou art covered with fatness; then he forsook God which made him."'),
('Deuteronomy', 32, 'adults', 4, 'What vivid description does Moses give of God''s anger and the nature of Israel''s punishment?', 'A fire kindled in God''s anger burning to the lowest hell, consuming the earth and mountains, and heaping mischiefs upon them', 'God''s anger described as a flood sweeping away the wicked as in the days of Noah', 'God''s wrath pictured as a consuming plague sent from the south wind', 'God''s judgment depicted as darkness covering the land for many years', 'a', 'Deuteronomy 32:22-23 — "For a fire is kindled in mine anger, and shall burn unto the lowest hell, and shall consume the earth with her increase, and set on fire the foundations of the mountains. I will heap mischiefs upon them."'),
('Deuteronomy', 32, 'adults', 5, 'Why did God restrain full judgment on Israel despite their apostasy, and what theological concern was cited?', 'God feared the enemy would misunderstand and claim their own hand had prevailed rather than the LORD', 'God was moved by the prayers of the remnant who had remained faithful to Him', 'God remembered His oath to Abraham and could not break His covenant entirely', 'God waited for Israel to repent so that His mercy might be shown to all nations', 'a', 'Deuteronomy 32:27 — "Were it not that I feared the wrath of the enemy, lest their adversaries should behave themselves strangely, and lest they should say, Our hand is high, and the LORD hath not done all this."'),
('Deuteronomy', 32, 'adults', 6, 'What does the Song of Moses say about Israel''s enemies and their vine, contrasting with Israel''s God?', 'Their vine is the vine of Sodom and the fields of Gomorrah; their grapes are grapes of gall and their wine the poison of dragons', 'Their vine withers because it is planted in foreign soil far from the presence of the LORD', 'Their vine produces no fruit because they worship idols that have no power to bless', 'Their vine is cut down and burned as God''s judgment on their wickedness', 'a', 'Deuteronomy 32:32 — "For their vine is of the vine of Sodom, and of the fields of Gomorrah: their grapes are grapes of gall, their clusters are bitter: Their wine is the poison of dragons, and the cruel venom of asps."'),
('Deuteronomy', 32, 'adults', 7, 'What does Moses say about the compassion God will show His people after judgment, and how is it framed?', 'God will repent for His servants when He sees their power is gone and none is shut up or left; He will avenge their blood', 'God will restore Israel after seventy years of captivity exactly as He foretold', 'God''s compassion will be triggered when Israel returns to keep all the commandments of the law', 'God will forgive Israel when they offer the proper sacrifices of atonement at the tabernacle', 'a', 'Deuteronomy 32:36 — "For the LORD shall judge his people, and repent himself for his servants, when he seeth that their power is gone, and there is none shut up, or left."'),
('Deuteronomy', 32, 'adults', 8, 'What instructions did God give Moses immediately after the song, connecting the song to Moses'' own imminent death?', 'God told Moses to go up to Mount Nebo and die there, because he had trespassed against God at Meribah-Kadesh', 'God told Moses to bless each tribe and then lie down among his people in peace', 'God told Moses to hand the written song to Joshua for safekeeping in the tabernacle', 'God told Moses to read the song to all Israel one final time in the plains of Moab', 'a', 'Deuteronomy 32:49-52 — "Get thee up into this mountain Abarim, unto mount Nebo...and die in the mount whither thou goest up...Because ye trespassed against me among the children of Israel at the waters of Meribah-Kadesh."');

-- ═══ Deuteronomy Chapter 33 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 33, 'kids', 1, 'What did Moses do for the twelve tribes of Israel before he died?', 'He blessed them', 'He tested them', 'He judged them', 'He named them', 'a', 'Deuteronomy 33:1 — "And this is the blessing, wherewith Moses the man of God blessed the children of Israel before his death."'),
('Deuteronomy', 33, 'kids', 2, 'What does Moses say is the eternal God to His people in Deuteronomy 33?', 'A refuge', 'A warrior', 'A shepherd', 'A judge', 'a', 'Deuteronomy 33:27 — "The eternal God is thy refuge, and underneath are the everlasting arms."'),
('Deuteronomy', 33, 'kids', 3, 'Which tribe did Moses say was "beloved of the LORD" and would dwell safely by Him?', 'Benjamin', 'Judah', 'Levi', 'Joseph', 'a', 'Deuteronomy 33:12 — "And of Benjamin he said, The beloved of the LORD shall dwell in safety by him; and the LORD shall cover him all the day long."'),
-- Teens
('Deuteronomy', 33, 'teens', 1, 'How does Moses describe God''s majestic appearance at the opening of his blessing?', 'God came from Sinai, rose from Seir, and shined forth from Mount Paran with ten thousands of saints', 'God appeared in a cloud of glory over the tabernacle and spoke with a great voice', 'God came as a pillar of fire to lead Moses up the mountain to pronounce the blessing', 'God descended from heaven on a chariot of cherubim as Moses prayed for Israel', 'a', 'Deuteronomy 33:2 — "The LORD came from Sinai, and rose up from Seir unto them; he shined forth from mount Paran, and he came with ten thousands of saints: from his right hand went a fiery law for them."'),
('Deuteronomy', 33, 'teens', 2, 'What honor did Moses give the tribe of Levi regarding the Urim, Thummim, and teaching?', 'Levi received the Urim and Thummim, was to teach Jacob God''s judgments, and to offer incense and burnt offerings', 'Levi was given the firstborn tithe of all Israel and the charge of the tabernacle furnishings', 'Levi was appointed as the personal guard of the high priest and the ark of the covenant', 'Levi was honored for refusing to worship the golden calf and given the Promised Land first', 'a', 'Deuteronomy 33:8-10 — "And of Levi he said, Let thy Thummim and thy Urim be with thy holy one...They shall teach Jacob thy judgments, and Israel thy law: they shall put incense before thee, and whole burnt sacrifice upon thine altar."'),
('Deuteronomy', 33, 'teens', 3, 'What does Moses prophesy would happen to enemies under the blessing on Joseph''s tribes?', 'The horns of Joseph would push the people together to the ends of the earth with the ten thousands of Ephraim and thousands of Manasseh', 'Joseph''s sons would defeat the Philistines and establish the kingdom in their land', 'The enemies of Joseph would flee before them seven ways and never recover', 'Joseph''s tribes would be given cities already built and vineyards already planted', 'a', 'Deuteronomy 33:17 — "His glory is like the firstling of his bullock, and his horns are like the horns of unicorns: with them he shall push the people together to the ends of the earth: and they are the ten thousands of Ephraim, and they are the thousands of Manasseh."'),
('Deuteronomy', 33, 'teens', 4, 'What blessing does Moses pronounce on Zebulun and Issachar, and what geographical element is involved?', 'They would rejoice in their going out and suck the abundance of the seas and treasures hid in the sand', 'They would receive the most fertile valleys and the richest farmland in Canaan', 'They would be given the great cities of the north and control the trade routes', 'They would multiply greatly and their descendants would fill the cities of Canaan', 'a', 'Deuteronomy 33:18-19 — "And of Zebulun he said, Rejoice, Zebulun, in thy going out...they shall suck of the abundance of the seas, and of treasures hid in the sand."'),
('Deuteronomy', 33, 'teens', 5, 'What great declaration closes Moses'' blessing, affirming Israel''s unique status before God?', 'Happy is Israel, a people saved by the LORD, whose sword of excellency and whose enemies shall be found liars', 'There is no nation as wise as Israel, for they alone received the law of the living God', 'Israel would be the head and not the tail among all nations of the earth forever', 'God would multiply Israel as the stars of heaven so that they could not be counted', 'a', 'Deuteronomy 33:29 — "Happy art thou, O Israel: who is like unto thee, O people saved by the LORD, the shield of thy help, and who is the sword of thy excellency! and thine enemies shall be found liars unto thee."'),
-- Adults
('Deuteronomy', 33, 'adults', 1, 'How does Moses characterize the covenant relationship and Israel''s status in his opening hymnic prologue to the blessings?', 'God loved the people, all His saints were in His hand, they sat down at His feet, and every one received His words', 'Moses declared that Israel had earned God''s favor by keeping the law in the wilderness', 'Moses reviewed the Exodus and Sinai covenant as the basis for God''s blessing on each tribe', 'Moses listed each tribe''s failures alongside the grace God showed them despite their sin', 'a', 'Deuteronomy 33:3 — "Yea, he loved the people; all his saints are in thy hand; and they sat down at thy feet; every one shall receive of thy words."'),
('Deuteronomy', 33, 'adults', 2, 'What specific historical crisis regarding Levi does Moses reference in the blessing, and what theological significance does it carry?', 'Levi''s faithfulness at the golden calf incident — "who said unto his father and mother, I have not seen him" — consecrated the tribe for priestly service', 'Levi''s refusal to rebel with Korah established their permanent right to the priesthood', 'Levi''s loyalty to Moses during the rebellion of the spies elevated them above the other tribes', 'Levi''s willingness to leave Egypt last, protecting the rear guard, earned them the priestly role', 'a', 'Deuteronomy 33:9 — "Who said unto his father and to his mother, I have not seen him; neither did he acknowledge his brethren, nor knew his own children: for they have observed thy word, and kept thy covenant."'),
('Deuteronomy', 33, 'adults', 3, 'What does Moses pray concerning those who rise against Levi''s ministry, and what does this reveal about sacerdotal protection?', 'Moses prays that God would smite through the loins of enemies that hate Levi so that they do not rise again', 'Moses prays that God would confuse the speech of those who challenge the Levitical priesthood', 'Moses prays that God would remove the inheritance of any tribe that despises the priests', 'Moses prays that God would send plague on the enemies of Levi as He did to Korah''s company', 'a', 'Deuteronomy 33:11 — "Smite through the loins of them that rise against him, and of them that hate him, that they rise not again."'),
('Deuteronomy', 33, 'adults', 4, 'What does Moses'' blessing of Dan — "Dan is a lion''s whelp: he shall leap from Bashan" — suggest about that tribe''s territorial destiny?', 'It suggests Dan''s aggressive military expansion from the northern region of Bashan in its later tribal migration', 'It suggests Dan would defend Israel''s eastern border from the lion-like enemies of Bashan', 'It suggests Dan would produce the greatest warrior-judges in Israel''s history', 'It suggests Dan''s territory would be given to them as spoil from the conquest of Bashan''s kingdoms', 'a', 'Deuteronomy 33:22 — "And of Dan he said, Dan is a lion''s whelp: he shall leap from Bashan."'),
('Deuteronomy', 33, 'adults', 5, 'What combination of natural blessings does Moses speak over Naphtali, and what theological framing is given?', 'Naphtali is satisfied with favour and full of the blessing of the LORD, possessing the west and the south', 'Naphtali is blessed with the most fruitful land and the most plentiful waters of any tribe', 'Naphtali is given peace on all borders and rest from warfare throughout their generations', 'Naphtali is blessed with wisdom and is called the tribe of scribes and teachers of Israel', 'a', 'Deuteronomy 33:23 — "And of Naphtali he said, O Naphtali, satisfied with favour, and full with the blessing of the LORD: possess thou the west and the south."'),
('Deuteronomy', 33, 'adults', 6, 'What does Moses say about Asher''s wealth and military security in the tribal blessing?', 'Asher is most blessed of sons, let him dip his foot in oil, and his shoes shall be iron and brass, and as his days so shall his strength be', 'Asher would receive the richest fields and would supply grain to all the northern tribes', 'Asher would be known for its craftsmen in bronze and iron who would equip Israel''s army', 'Asher would have borders defended by natural mountains making them impenetrable by enemies', 'a', 'Deuteronomy 33:24-25 — "And of Asher he said, Let Asher be blessed with children; let him be acceptable to his brethren, and let him dip his foot in oil. Thy shoes shall be iron and brass; and as thy days, so shall thy strength be."'),
('Deuteronomy', 33, 'adults', 7, 'What two actions does Moses describe God performing on behalf of Israel against its enemies in the land?', 'God will thrust out the enemy before them and say "Destroy them," so Israel shall dwell in safety alone', 'God will send His angel ahead and cause confusion among the nations so they flee', 'God will give Israel chariots of fire and horses to defeat every army they face', 'God will dry up the rivers and wither the crops of Israel''s enemies until they surrender', 'a', 'Deuteronomy 33:27 — "The eternal God is thy refuge, and underneath are the everlasting arms: and he shall thrust out the enemy from before thee; and shall say, Destroy them."'),
('Deuteronomy', 33, 'adults', 8, 'How does Moses conclude the blessing by comparing Israel to other nations in terms of divine protection?', 'Israel is uniquely saved by the LORD whose shield and sword of excellency cause enemies to be found liars; Israel dwells safely under a heaven dropping dew', 'Israel is the greatest nation because they alone received the written law on tablets of stone from God Himself', 'Israel surpasses all nations in wisdom because they were taught directly by Moses, the friend of God', 'Israel is supreme among nations because they are the only people descended from Abraham, Isaac, and Jacob', 'a', 'Deuteronomy 33:28-29 — "Israel then shall dwell in safety alone: the fountain of Jacob shall be upon a land of corn and wine; also his heavens shall drop down dew. Happy art thou, O Israel: who is like unto thee, O people saved by the LORD?"');

-- ═══ Deuteronomy Chapter 34 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 34, 'kids', 1, 'Where did Moses go to see the Promised Land before he died?', 'To the top of Mount Pisgah', 'To the top of Mount Sinai', 'To the shore of the Jordan River', 'To the top of Mount Carmel', 'a', 'Deuteronomy 34:1 — "And Moses went up from the plains of Moab unto the mountain of Nebo, to the top of Pisgah, that is over against Jericho."'),
('Deuteronomy', 34, 'kids', 2, 'How old was Moses when he died?', 'One hundred and twenty years old', 'One hundred years old', 'Eighty years old', 'One hundred and ten years old', 'a', 'Deuteronomy 34:7 — "And Moses was an hundred and twenty years old when he died: his eye was not dim, nor his natural force abated."'),
('Deuteronomy', 34, 'kids', 3, 'Who took over as the leader of Israel after Moses died?', 'Joshua', 'Caleb', 'Aaron', 'Phinehas', 'a', 'Deuteronomy 34:9 — "And Joshua the son of Nun was full of the spirit of wisdom; for Moses had laid his hands upon him: and the children of Israel hearkened unto him."'),
-- Teens
('Deuteronomy', 34, 'teens', 1, 'What panoramic view did God show Moses from Mount Pisgah, and what promise accompanied it?', 'God showed Moses all the land from Gilead to Dan, Naphtali, Ephraim, Manasseh, Judah to the sea, the south, and the plain of Jericho — the land He swore to Abraham, Isaac, and Jacob', 'God showed Moses Jerusalem and the temple mount where His name would dwell forever', 'God showed Moses the great cities of Canaan that Israel would conquer and inhabit', 'God showed Moses the whole world so he could understand the scope of His creation', 'a', 'Deuteronomy 34:1-4 — "And the LORD shewed him all the land of Gilead, unto Dan, And all Naphtali, and the land of Ephraim, and Manasseh, and all the land of Judah, unto the utmost sea...This is the land which I sware unto Abraham, unto Isaac, and unto Jacob."'),
('Deuteronomy', 34, 'teens', 2, 'What remarkable physical details are given about Moses at the time of his death?', 'His eye was not dim nor his natural force abated even at one hundred and twenty years old', 'His hair was still dark and his hands were still strong for writing', 'His voice was clear and his face still shone from speaking with God', 'His mind was sharp and he could still march with the army', 'a', 'Deuteronomy 34:7 — "And Moses was an hundred and twenty years old when he died: his eye was not dim, nor his natural force abated."'),
('Deuteronomy', 34, 'teens', 3, 'Who buried Moses, and what is mysterious about his burial place?', 'The LORD buried him in a valley in Moab, and no man knows where his sepulchre is to this day', 'The Levites buried Moses in a tomb on Mount Nebo which was later sealed with stones', 'The elders of Israel buried Moses secretly so that Israel would not mourn too long', 'Moses was buried by angels on the mountain, and the place was made holy ground', 'a', 'Deuteronomy 34:6 — "And he buried him in a valley in the land of Moab, over against Beth-peor: but no man knoweth of his sepulchre unto this day."'),
('Deuteronomy', 34, 'teens', 4, 'How long did the children of Israel weep for Moses in the plains of Moab?', 'Thirty days', 'Forty days', 'Seven days', 'Seventy days', 'a', 'Deuteronomy 34:8 — "And the children of Israel wept for Moses in the plains of Moab thirty days: so the days of weeping and mourning for Moses were ended."'),
('Deuteronomy', 34, 'teens', 5, 'How does the book of Deuteronomy conclude its assessment of Moses compared to all other prophets in Israel?', 'There arose not a prophet since in Israel like Moses, whom the LORD knew face to face', 'Moses was greater than all prophets because he wrote the first five books of the Bible', 'Moses surpassed all prophets because he performed more miracles than any other man', 'Moses was unequalled because he alone ascended to heaven while still living', 'a', 'Deuteronomy 34:10 — "And there arose not a prophet since in Israel like unto Moses, whom the LORD knew face to face."'),
-- Adults
('Deuteronomy', 34, 'adults', 1, 'What is the theological significance of God Himself burying Moses in an unknown location, as understood in later Jewish and Christian tradition?', 'It prevented the grave from becoming an idolatrous shrine and emphasized that Moses was servant of God rather than an object of worship', 'It demonstrated God''s anger at Moses'' sin at Meribah by denying him a proper burial with the patriarchs', 'It proved that Moses had ascended bodily to heaven as Elijah would later do', 'It fulfilled a prophecy that a man of God would be buried in foreign soil as a sign to Israel', 'a', 'Deuteronomy 34:6 — "And he buried him in a valley in the land of Moab, over against Beth-peor: but no man knoweth of his sepulchre unto this day."'),
('Deuteronomy', 34, 'adults', 2, 'What does the Spirit of wisdom given to Joshua through Moses'' laying on of hands suggest about the nature of prophetic succession?', 'It shows that spiritual authority could be transferred through ordained laying on of hands, and Israel''s obedience to Joshua was tied to recognition of this transferred anointing', 'It shows that Joshua earned his leadership through decades of faithful military service under Moses', 'It shows that the spirit of wisdom was a permanent gift given to all commanders of Israel''s army', 'It shows that Moses'' own spirit literally departed from him and entered Joshua at the moment of transfer', 'a', 'Deuteronomy 34:9 — "And Joshua the son of Nun was full of the spirit of wisdom; for Moses had laid his hands upon him: and the children of Israel hearkened unto him, and did as the LORD commanded Moses."'),
('Deuteronomy', 34, 'adults', 3, 'The phrase "whom the LORD knew face to face" — how does this compare with God''s own earlier declaration about Moses'' unique prophetic standing?', 'Numbers 12:6-8 establishes that ordinary prophets received visions and dreams, but with Moses God spoke "mouth to mouth, even apparently, and not in dark speeches," making Deuteronomy 34 the narrative confirmation of that unique standing', 'Exodus 33:11 says God spoke to Moses as a man speaks to his friend, and Deuteronomy 34 confirms this was unique among all prophets', 'Both Numbers 12 and Deuteronomy 34 use the same phrase "face to face" as an exact quote demonstrating editorial unity', 'The phrase refers primarily to Moses'' role as covenant mediator rather than to his personal intimacy with God', 'a', 'Deuteronomy 34:10 — "And there arose not a prophet since in Israel like unto Moses, whom the LORD knew face to face."'),
('Deuteronomy', 34, 'adults', 4, 'What three categories of mighty power does the text cite as the basis for Moses'' incomparable prophetic status?', 'Signs and wonders in Egypt, mighty acts of terror, and all the great terror which Moses shewed in the sight of all Israel', 'The giving of the law, the building of the tabernacle, and the conquest of Sihon and Og', 'The ten plagues, the parting of the Red Sea, and the giving of the Ten Commandments', 'The manna, the water from the rock, and the pillar of cloud and fire', 'a', 'Deuteronomy 34:11-12 — "In all the signs and the wonders, which the LORD sent him to do in the land of Egypt...And in all that mighty hand, and in all the great terror which Moses shewed in the sight of all Israel."'),
('Deuteronomy', 34, 'adults', 5, 'What is the structural and canonical significance of Deuteronomy 34 ending the Torah, and how does it point forward to the rest of the Hebrew canon?', 'It marks the close of the Mosaic era and positions all subsequent Scripture as commentary on the Mosaic covenant, while the unfulfilled promise of the land points forward to Joshua and the continuation of redemptive history', 'It provides a biographical conclusion to Moses'' life that mirrors the Genesis account of creation concluding with rest', 'It ends the Torah with an unresolved tension that is only resolved in the New Testament by Christ''s greater lawgiving in the Sermon on the Mount', 'It closes with prophecy about a coming prophet greater than Moses that is immediately fulfilled in Joshua', 'a', 'Deuteronomy 34:4 — "This is the land which I sware unto Abraham, unto Isaac, and unto Jacob, saying, I will give it unto thy seed: I have caused thee to see it with thine eyes, but thou shalt not go over thither."'),
('Deuteronomy', 34, 'adults', 6, 'What does the mourning period of thirty days for Moses parallel in the rest of the Old Testament narrative?', 'It exactly parallels the thirty days of mourning for Aaron in Numbers 20:29, establishing a consistent period of national grief for the death of foundational leaders', 'It parallels the seven days of mourning observed for Job''s suffering as described in Job 2:13', 'It parallels the forty days of fasting that Moses himself observed on Sinai before receiving the law', 'It parallels the period of Nazirite vows which were also thirty days in duration', 'a', 'Deuteronomy 34:8 — "And the children of Israel wept for Moses in the plains of Moab thirty days: so the days of weeping and mourning for Moses were ended."'),
('Deuteronomy', 34, 'adults', 7, 'What does the detail "his eye was not dim, nor his natural force abated" suggest theologically about Moses'' death?', 'It indicates Moses'' death was entirely an act of divine will rather than natural aging — God took him precisely when appointed, not because his body gave out', 'It demonstrates that righteous men in the Old Testament did not experience the physical decline associated with the fall', 'It proves that Moses had been supernaturally rejuvenated on Sinai during his two forty-day fasts', 'It shows that the law given through Moses was a source of physical as well as spiritual vitality', 'a', 'Deuteronomy 34:7 — "And Moses was an hundred and twenty years old when he died: his eye was not dim, nor his natural force abated."'),
('Deuteronomy', 34, 'adults', 8, 'How does the land promised to the patriarchs — named specifically to Abraham, Isaac, and Jacob — function as a theological bookend connecting Deuteronomy 34 back to Genesis?', 'God''s words "This is the land which I sware unto Abraham, unto Isaac, and unto Jacob" directly echo the Abrahamic covenant in Genesis, showing the entire Pentateuch as one arc of promise awaiting fulfillment', 'The naming of the three patriarchs was Moses'' final act of teaching so Israel would remember their origins in Mesopotamia', 'The promise to the patriarchs is restated here to remind Joshua that his authority derived from the covenant made with Abraham', 'The land promise functions as a warning that Israel must keep all of Moses'' law or forfeit the inheritance given to the fathers', 'a', 'Deuteronomy 34:4 — "And the LORD said unto him, This is the land which I sware unto Abraham, unto Isaac, and unto Jacob, saying, I will give it unto thy seed: I have caused thee to see it with thine eyes, but thou shalt not go over thither."');
